  1→import { distance } from '@/geometry/point';
  2→import { distanceToSegment } from '@/geometry/line';
  3→import { doorOutlineOnWall, windowOutlineOnWall, wallLength, wallOutline, projectPointOnWall } from '@/geometry/wallGeometry';
  4→import { pointInPolygon } from '@/geometry/polygon';
  5→
  6→function hitTest(modelPos, floor, hitRadius) {
  7→  // Hit test doors first (smaller targets, higher priority)
  8→  for (const door of floor.doors) {
  9→    const wall = floor.walls.find(w => w.id === door.wallId);
 10→    if (!wall) continue;
 11→    const info = doorOutlineOnWall(wall, door);
 12→    const poly = [info.p1, info.p2, info.p3, info.p4];
 13→    if (pointInPolygon(modelPos, poly)) {
 14→      return { id: door.id, type: 'door' };
 15→    }
 16→  }
 17→
 18→  // Hit test windows
 19→  for (const win of floor.windows) {
 20→    const wall = floor.walls.find(w => w.id === win.wallId);
 21→    if (!wall) continue;
 22→    const info = windowOutlineOnWall(wall, win);
 23→    const poly = [info.p1, info.p2, info.p3, info.p4];
 24→    if (pointInPolygon(modelPos, poly)) {
 25→      return { id: win.id, type: 'window' };
 26→    }
 27→  }
 28→
 29→  // Hit test walls
 30→  for (const wall of floor.walls) {
 31→    const outline = wallOutline(wall);
 32→    if (pointInPolygon(modelPos, outline)) {
 33→      return { id: wall.id, type: 'wall' };
 34→    }
 35→  }
 36→
 37→  // Hit test rooms (lowest priority)
 38→  for (const room of floor.rooms) {
 39→    if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
 40→      return { id: room.id, type: 'room' };
 41→    }
 42→  }
 43→
 44→  return null;
 45→}
 46→
 47→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport }) {
 48→  return {
 49→    onMouseDown(modelPos, e, toolState) {
 50→      if (e.button !== 0) return;
 51→
 52→      const floor = getFloor(activeFloorId);
 53→      const hitRadius = 10 / viewport.zoom;
 54→
 55→      // Check if clicking a handle
 56→      const target = e.target;
 57→      if (target.dataset.handle) {
 58→        editorDispatch({
 59→          type: 'UPDATE_TOOL_STATE',
 60→          payload: {
 61→            dragging: true,
 62→            dragType: 'handle',
 63→            handle: target.dataset.handle,
 64→            startPos: modelPos,
 65→          },
 66→        });
 67→        return;
 68→      }
 69→
 70→      const hit = hitTest(modelPos, floor, hitRadius);
 71→      if (hit) {
 72→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
 73→        editorDispatch({
 74→          type: 'UPDATE_TOOL_STATE',
 75→          payload: {
 76→            dragging: true,
 77→            dragType: 'move',
 78→            startPos: modelPos,
 79→            originalPos: modelPos,
 80→          },
 81→        });
 82→      } else {
 83→        editorDispatch({ type: 'DESELECT' });
 84→      }
 85→    },
 86→
 87→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
 88→      if (!toolState.dragging || !selectedId) return;
 89→
 90→      const floor = getFloor(activeFloorId);
 91→      const dx = modelPos.x - toolState.startPos.x;
 92→      const dy = modelPos.y - toolState.startPos.y;
 93→
 94→      if (selectedType === 'wall') {
 95→        const wall = floor.walls.find(w => w.id === selectedId);
 96→        if (!wall) return;
 97→
 98→        if (toolState.dragType === 'handle') {
 99→          const handle = toolState.handle;
100→          dispatch({
101→            type: 'WALL_UPDATE',
102→            floorId: activeFloorId,
103→            wall: {
104→              id: wall.id,
105→              [handle]: { x: modelPos.x, y: modelPos.y },
106→            },
107→          });
108→        } else {
109→          dispatch({
110→            type: 'WALL_UPDATE',
111→            floorId: activeFloorId,
