 48→      if (d < bestDist) {
 49→        best = point;
 50→        bestDist = d;
 51→      }
 52→    }
 53→  }
 54→
 55→  return best;
 56→}
 57→
 58→function constrainAngle(start, end, shiftHeld) {
 59→  if (!shiftHeld) return end;
 60→  const dx = end.x - start.x;
 61→  const dy = end.y - start.y;
 62→  const angle = Math.atan2(dy, dx);
 63→  const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
 64→  const len = Math.sqrt(dx * dx + dy * dy);
 65→  return {
 66→    x: start.x + Math.cos(snapAngle) * len,
 67→    y: start.y + Math.sin(snapAngle) * len,
 68→  };
 69→}
 70→
 71→export function createWallDrawHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
 72→  return {
 73→    onMouseDown(modelPos, e, toolState) {
 74→      if (e.button !== 0) return;
 75→
 76→      const floor = getFloor(activeFloorId);
 77→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
 78→      const shiftHeld = e.shiftKey;
 79→
 80→      let snapped = modelPos;
 81→      if (snapEnabled) {
 82→        const snapPt = snapToWalls(modelPos, floor.walls, snapDistModel, toolState.chainStart, floor.columns);
 83→        if (snapPt) snapped = { ...snapPt };
 84→      }
 85→      if (shiftHeld && toolState.start) {
 86→        snapped = constrainAngle(toolState.start, snapped, true);
 87→      }
 88→
 89→      if (!toolState.start) {
 90→        // First click: set start
 91→        editorDispatch({
 92→          type: 'UPDATE_TOOL_STATE',
 93→          payload: { start: snapped, chainStart: snapped, preview: null },
 94→        });
 95→      } else {
 96→        // Second+ click: create wall and chain
 97→        const endPt = snapped;
 98→
 99→        const len = distance(toolState.start, endPt);
100→        if (len < MIN_WALL_LENGTH) return;
101→
102→        const wall = createWall(toolState.start, endPt);
103→        dispatch({ type: 'WALL_ADD', floorId: activeFloorId, wall });
104→
105→        // Check if we snapped back to chain start (close loop)
106→        if (toolState.chainStart && distance(endPt, toolState.chainStart) < snapDistModel) {
107→          editorDispatch({
108→            type: 'UPDATE_TOOL_STATE',
109→            payload: { start: null, chainStart: null, preview: null },
110→          });
111→        } else {
112→          // Chain: end becomes new start
113→          editorDispatch({
114→            type: 'UPDATE_TOOL_STATE',
115→            payload: { start: endPt, preview: null },
116→          });
117→        }
118→      }
119→    },
120→
121→    onMouseMove(modelPos, e, toolState) {
122→      if (!toolState.start) return;
123→      let preview = modelPos;
124→
125→      const floor = getFloor(activeFloorId);
126→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
127→      if (snapEnabled) {
128→        const snapPt = snapToWalls(modelPos, floor.walls, snapDistModel, toolState.chainStart, floor.columns);
129→        if (snapPt) preview = { ...snapPt };
130→      }
131→      if (e.shiftKey) {
132→        preview = constrainAngle(toolState.start, preview, true);
133→      }
134→
135→      editorDispatch({
136→        type: 'UPDATE_TOOL_STATE',
137→        payload: { preview },
138→      });
139→    },
140→
141→    onDoubleClick(modelPos, e, toolState) {
142→      // Finish chain
143→      editorDispatch({
144→        type: 'UPDATE_TOOL_STATE',
145→        payload: { start: null, chainStart: null, preview: null },
146→      });
147→    },
148→
149→    onKeyDown(e, toolState) {
150→      if (e.key === 'Escape') {
151→        editorDispatch({
152→          type: 'UPDATE_TOOL_STATE',
153→          payload: { start: null, chainStart: null, preview: null },
154→        });
155→      }
156→    },
157→
158→    getCursor(toolState) {
159→      return 'crosshair';
160→    },
161→  };
162→}
