import { TOOLS } from '@/editor/tools';
import { distance } from '@/geometry/point';
import { PREVIEW_LABEL_OFFSET } from '@/domain/defaults';

export default function WallPreview({ toolState, activeTool }) {
  if (activeTool !== TOOLS.WALL || !toolState.start || !toolState.preview) {
    return null;
  }

  const { start, preview } = toolState;
  const len = distance(start, preview);
  const label = (len / 1000).toFixed(2) + ' m';
  const midX = (start.x + preview.x) / 2;
  const midY = (start.y + preview.y) / 2;

  return (
    <g className="wall-preview" style={{ pointerEvents: 'none' }}>
      <line
        x1={start.x} y1={start.y}
        x2={preview.x} y2={preview.y}
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="8 4"
        vectorEffect="non-scaling-stroke"
        opacity={0.7}
      />
      <circle
        cx={start.x} cy={start.y} r={4}
        fill="var(--color-selection)"
        vectorEffect="non-scaling-stroke"
      />
      <circle
        cx={preview.x} cy={preview.y} r={4}
        fill="var(--color-selection)"
        vectorEffect="non-scaling-stroke"
      />
      <text
        x={midX} y={midY}
        textAnchor="middle"
        dy={-PREVIEW_LABEL_OFFSET}
        fill="var(--color-selection)"
        fontSize={140}
        fontFamily="var(--font-blueprint)"
      >
        {label}
      </text>
    </g>
  );
}

input.prompt:
Design an implementation plan for refining wall-column interaction in a 2D apartment blueprint editor.

## Context

Columns were just added to the editor. Currently:
- `columnSnapPoints()` returns center + 4 corners (5 points)
- `wallDrawHandler.js` snaps wall endpoints to those 5 points via `snapToWalls()` 
- Walls render as full rectangles, columns render on top — no clipping or visual termination
- All geometry is in mm, SVG rendering with zoom transform

## Requirements
1. Allow wall endpoints to snap to column corners AND column centerlines (edge midpoints)
2. Support walls "terminating at column faces" — visual alignment so walls look clean against columns
3. Visually align walls and columns cleanly in plan view
4. Keep geometry logic modular (new functions in columnGeometry.js)
5. Do NOT rewrite unrelated parts

## Current Code State

### columnGeometry.js (full file)
```js
import { rotate } from './point';

export function columnOutline(column) {
  const hw = column.width / 2, hd = column.depth / 2;
  const { x: cx, y: cy } = column;
  const corners = [
    { x: cx - hw, y: cy - hd }, { x: cx + hw, y: cy - hd },
    { x: cx + hw, y: cy + hd }, { x: cx - hw, y: cy + hd },
  ];
  if (!column.rotation) return corners;
  return corners.map(p => rotate(p, { x: cx, y: cy }, column.rotation));
}

export function columnSnapPoints(column) {
  return [{ x: column.x, y: column.y }, ...columnOutline(column)];
}
```

### wallDrawHandler.js — snapToWalls function
```js
function snapToWalls(modelPos, walls, snapDistModel, chainStart, columns) {
  let best = null;
  let bestDist = snapDistModel;

  // Snap to chain start to close loop
  if (chainStart) {
    const d = distance(modelPos, chainStart);
    if (d < bestDist) { best = chainStart; bestDist = d; }
  }

  // Snap to wall endpoints
  for (const wall of walls) {
    for (const pt of [wall.start, wall.end]) {
      const d = distance(modelPos, pt);
      if (d < bestDist) { best = pt; bestDist = d; }
    }
  }

  // Snap to column points (center + corners)
  for (const column of (columns || [])) {
    for (const pt of columnSnapPoints(column)) {
      const d = distance(modelPos, pt);
      if (d < bestDist) { best = pt; bestDist = d; }
    }
  }

  // If no endpoint found, try snapping to nearest point on wall segments
  if (!best) {
    for (const wall of walls) {
      const { point, t } = nearestPointOnSegment(modelPos, wall.start, wall.end);
      if (t <= 0.001 || t >= 0.999) continue;
      const d = distance(modelPos, point);
      if (d < bestDist) { best = point; bestDist = d; }
    }
  }

  return best;
}
```

### wallGeometry.js — wallOutline
```js
export function wallOutline(wall) {
  const dir = normalize(subtract(wall.end, wall.start));
  const perp = perpendicular(dir);
  const halfThick = wall.thickness / 2;
  const offset = scale(perp, halfThick);
  return [
    add(wall.start, offset),
    add(wall.end, offset),
    subtract(wall.end, offset),
    subtract(wall.start, offset),
  ];
}
```

### line.js — available utilities
- `nearestPointOnSegment(p, a, b)` → { point, t }
- `distanceToSegment(p, a, b)` → number
- `segmentLength(a, b)` → number
- `segmentIntersection(a1, a2, b1, b2)` → point | null

### point.js — available utilities
- `distance`, `midpoint`, `lerp`, `rotate`, `add`, `subtract`, `scale`, `normalize`, `perpendicular`, `dot`

### Rendering order (SvgCanvas.jsx)
Rooms → Walls → Columns → Doors → Windows → Dimensions → SelectionOverlay → Previews

Columns render AFTER walls, so columns visually sit on top.

## Key Design Questions

1. **Edge midpoints**: Should `columnSnapPoints` be expanded to include midpoints of all 4 edges? This gives 9 snap points total (center + 4 corners + 4 edge midpoints).

2. **Centerline snapping**: "Centerlines" in architectural terms means the horizontal and vertical axes through column center. When a wall endpoint is near a column, should it snap to the nearest point on a column edge along these centerlines? This effectively means snapping to edge midpoints (which are where centerlines intersect the edges).

3. **Wall termination at column face**: When a wall endpoint snaps to a column, the wall currently extends its centerline to that point. For clean visual alignment:
   - Option A: Snap the wall endpoint to the column face (edge midpoint), so the wall meets the column surface cleanly. This is already achievable if we add edge midpoints to snap points.
   - Option B: Clip/extend the wall outline polygon so it visually terminates exactly at the column face. This requires modifying wallOutline or the renderer to account for columns — much more complex.
   - Option C: Since columns render on top of walls, if a wall's centerline endpoint is at the column center, the wall rectangle extends INTO the column and the column covers it. This already looks clean for walls approaching the center. For walls approaching a face, snapping to edge midpoints handles it.

4. **Visual alignment**: With columns rendering on top of walls, a wall endpoint at column center means the wall extends into/through the column and the column covers the overlap. This is architecturally correct (walls embed into columns). Combined with edge midpoint snaps, this should look clean without any clipping.

Please design a focused, minimal plan that achieves the requirements. Consider which approach gives the best visual result with the least complexity.

