 20→function screenToModel(screenX, screenY, viewport, svgRect) {
 21→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 22→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 23→  return { x, y };
 24→}
 25→
 26→export default function SvgCanvas() {
 27→  const svgRef = useRef(null);
 28→  const isPanning = useRef(false);
 29→  const lastPanPos = useRef({ x: 0, y: 0 });
 30→  const spaceHeld = useRef(false);
 31→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 32→
 33→  const { project, dispatch, getFloor } = useProject();
 34→  const editor = useEditor();
 35→  const {
 36→    activeTool, selectedId, selectedType, toolState,
 37→    viewport, showGrid, snapEnabled, activeFloorId,
 38→    dispatch: editorDispatch,
 39→  } = editor;
 40→
 41→  const floor = getFloor(activeFloorId);
 42→
 43→  const tool = useEditorTool({
 44→    activeTool,
 45→    dispatch,
 46→    editorDispatch,
 47→    getFloor,
 48→    activeFloorId,
 49→    viewport,
 50→    snapEnabled,
 51→    selectedId,
 52→    selectedType,
 53→    toolState,
 54→  });
 55→
 56→  const getModelPos = useCallback((e) => {
 57→    const rect = svgRef.current.getBoundingClientRect();
 58→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 59→  }, [viewport]);
 60→
 61→  const handleMouseDown = useCallback((e) => {
 62→    // Middle mouse or space+left for pan
 63→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 64→      isPanning.current = true;
 65→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 66→      e.preventDefault();
 67→      return;
 68→    }
 69→
 70→    const modelPos = getModelPos(e);
 71→    tool.onMouseDown(modelPos, e);
 72→  }, [getModelPos, tool]);
 73→
 74→  const handleMouseMove = useCallback((e) => {
 75→    if (isPanning.current) {
 76→      const dx = e.clientX - lastPanPos.current.x;
 77→      const dy = e.clientY - lastPanPos.current.y;
 78→      editorDispatch({ type: 'PAN', dx, dy });
 79→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 80→      return;
 81→    }
 82→
 83→    const modelPos = getModelPos(e);
 84→    setCursorPos(modelPos);
 85→    tool.onMouseMove(modelPos, e);
 86→  }, [getModelPos, tool, editorDispatch]);
 87→
 88→  const handleMouseUp = useCallback((e) => {
 89→    if (isPanning.current) {
 90→      isPanning.current = false;
 91→      return;
 92→    }
 93→    const modelPos = getModelPos(e);
 94→    tool.onMouseUp(modelPos, e);
 95→  }, [getModelPos, tool]);
 96→
 97→  const handleDoubleClick = useCallback((e) => {
 98→    const modelPos = getModelPos(e);
 99→    tool.onDoubleClick(modelPos, e);
100→  }, [getModelPos, tool]);
101→
102→  const handleWheel = useCallback((e) => {
103→    e.preventDefault();
104→    const rect = svgRef.current.getBoundingClientRect();
105→    const mouseX = e.clientX - rect.left;
106→    const mouseY = e.clientY - rect.top;
107→
108→    const direction = e.deltaY < 0 ? 1 : -1;
109→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
110→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
111→
112→    // Zoom centered on cursor
113→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
114→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
115→
116→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
117→  }, [viewport, editorDispatch]);
118→
119→  useEffect(() => {
120→    const handleKeyDown = (e) => {
121→      if (e.key === ' ') {
122→        spaceHeld.current = true;
123→        e.preventDefault();
124→      }
125→
126→      // Tool shortcuts
127→      if (!e.ctrlKey && !e.metaKey) {
128→        switch (e.key.toLowerCase()) {
129→          case 'v':
130→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
131→            return;
132→          case 'w':
133→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
134→            return;
135→          case 'd':
136→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
137→            return;
138→          case 'n':
139→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
140→            return;
141→          case 'c':
142→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
143→            return;
144→        }
145→      }
146→
147→      tool.onKeyDown(e);
148→    };
149→
150→    const handleKeyUp = (e) => {
151→      if (e.key === ' ') {
152→        spaceHeld.current = false;
153→      }
154→    };
155→
156→    window.addEventListener('keydown', handleKeyDown);
157→    window.addEventListener('keyup', handleKeyUp);
158→    return () => {
159→      window.removeEventListener('keydown', handleKeyDown);
160→      window.removeEventListener('keyup', handleKeyUp);
161→    };
162→  }, [tool, editorDispatch]);
163→
164→  // Prevent default context menu on SVG
165→  useEffect(() => {
166→    const svg = svgRef.current;
167→    if (!svg) return;
168→    const prevent = (e) => e.preventDefault();
169→    svg.addEventListener('contextmenu', prevent);
170→    svg.addEventListener('wheel', handleWheel, { passive: false });
171→    return () => {
172→      svg.removeEventListener('contextmenu', prevent);
173→      svg.removeEventListener('wheel', handleWheel);
174→    };
175→  }, [handleWheel]);
176→
177→  const cursor = spaceHeld.current ? 'grab' : tool.getCursor();
178→  const zoomPercent = Math.round(viewport.zoom * 1000);
179→
180→  return (
181→    <div className={styles.canvasContainer}>
182→      <svg
183→        ref={svgRef}
184→        className={styles.svg}
185→        style={{ cursor }}
186→        onMouseDown={handleMouseDown}
187→        onMouseMove={handleMouseMove}
188→        onMouseUp={handleMouseUp}
189→        onDoubleClick={handleDoubleClick}
190→      >
191→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
192→          {showGrid && <GridRenderer />}
193→          {showGrid && (
194→            <rect
195→              x={-100000} y={-100000}
196→              width={200000} height={200000}
197→              fill="url(#grid-major)"
198→              style={{ pointerEvents: 'none' }}
199→            />
200→          )}
201→          {floor && (
202→            <>
203→              <RoomRenderer rooms={floor.rooms} selectedId={selectedId} />
204→              <WallRenderer walls={floor.walls} />
205→              <ColumnRenderer columns={floor.columns || []} />
206→              <DoorRenderer doors={floor.doors} walls={floor.walls} />
207→              <WindowRenderer windows={floor.windows} walls={floor.walls} />
208→              <DimensionRenderer walls={floor.walls} />
209→              <SelectionOverlay
210→                selectedId={selectedId}
211→                selectedType={selectedType}
212→                floor={floor}
213→                zoom={viewport.zoom}
214→              />
215→              <WallPreview toolState={toolState} activeTool={activeTool} />
216→              <DoorWindowPreview
217→                toolState={toolState}
218→                activeTool={activeTool}
219→                walls={floor.walls}
220→              />
221→              <ColumnPreview toolState={toolState} activeTool={activeTool} />
222→            </>
223→          )}
224→        </g>
225→      </svg>
226→      <div className={styles.statusBar}>
227→        <span>X: {Math.round(cursorPos.x)} mm</span>
228→        <span>Y: {Math.round(cursorPos.y)} mm</span>
229→        <span>Zoom: {zoomPercent}%</span>
230→        <span>Tool: {activeTool}</span>
231→      </div>
232→    </div>
233→  );
234→}
