 8→export function createColumnPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId, snapEnabled }) {
 9→  return {
10→    onMouseMove(modelPos) {
11→      let x = modelPos.x;
12→      let y = modelPos.y;
13→      if (snapEnabled) {
14→        x = snapToGrid(x);
