 9→export function useEditorTool({ activeTool, dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled, selectedId, selectedType, toolState }) {
10→  const getFloorRef = useRef(getFloor);
11→  getFloorRef.current = getFloor;
12→
13→  const handler = useMemo(() => {
14→    const ctx = {
15→      dispatch, editorDispatch,
16→      getFloor: (...args) => getFloorRef.current(...args),
17→      activeFloorId, viewport, snapEnabled,
18→    };
19→
20→    switch (activeTool) {
21→      case TOOLS.WALL:
22→        return createWallDrawHandler(ctx);
23→      case TOOLS.SELECT:
24→        return createSelectHandler(ctx);
25→      case TOOLS.DOOR:
26→        return createDoorPlaceHandler(ctx);
27→      case TOOLS.WINDOW:
28→        return createWindowPlaceHandler(ctx);
29→      case TOOLS.COLUMN:
30→        return createColumnPlaceHandler(ctx);
31→      default:
32→        return null;
33→    }
34→  }, [activeTool, activeFloorId, viewport.zoom, snapEnabled]);
35→
36→  return {
37→    onMouseDown: (modelPos, e) => handler?.onMouseDown?.(modelPos, e, toolState),
38→    onMouseMove: (modelPos, e) => handler?.onMouseMove?.(modelPos, e, toolState, selectedId, selectedType),
39→    onMouseUp: (modelPos, e) => handler?.onMouseUp?.(modelPos, e, toolState),
40→    onDoubleClick: (modelPos, e) => handler?.onDoubleClick?.(modelPos, e, toolState),
41→    onKeyDown: (e) => handler?.onKeyDown?.(e, toolState, selectedId, selectedType),
42→    getCursor: () => handler?.getCursor?.(toolState) || 'default',
43→  };
44→}
